using namespace std;
int main() {
    int a = 1000000000;  // 1 billion (fits in int)
    int b = 3;

    // WRONG: int * int overflows!
    cout << a * b << "\n";           // Prints: -294967296  (overflow!)

    // CORRECT: cast to long long first
    cout << (long long)a * b << "\n"; // Prints: 3000000000

    // ALSO CORRECT: use long long variables
    long long x = 1000000000LL;
    cout << x * b << "\n";            // Prints: 3000000000
    return 0;
}

