#include <bits/stdc++.h>
using namespace std;
int main() {
    // Integer division (truncates toward zero)
    cout << 7 / 2 << "\n";      // 3
    cout << -7 / 2 << "\n";     // -3 (not -4!  truncates TOWARD ZERO)
    cout << 7 % 2 << "\n";      // 1
    cout << -7 % 2 << "\n";     // -1 (sign follows dividend in C++)

    // Bitwise operators (crucial for CP)
    int x = 12;   // binary: 1100
    int y = 10;   // binary: 1010
    cout << (x & y) << "\n";   // AND:  1000 = 8
    cout << (x | y) << "\n";   // OR:   1110 = 14
    cout << (x ^ y) << "\n";   // XOR:  0110 = 6
    cout << (~x) << "\n";      // NOT: -13 (two's complement)
    cout << (x << 1) << "\n";  // Left shift = multiply by 2: 24
    cout << (x >> 1) << "\n";  // Right shift = divide by 2: 6

    // Ternary operator
    int a = 5, b = 3;
    int mx = (a > b) ? a : b;   // max(a,b) = 5
    cout << mx << "\n";
    return 0;
}

