#include <bits/stdc++.h>
using namespace std;
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cin >> n;

    long long sum = 0;   // Use long long to avoid overflow
    for (int i = 0; i < n; i++) {
        long long val;
        cin >> val;
        sum += val;
    }

    cout << sum << "\n";
    return 0;
}

