#include <bits/stdc++.h>
using namespace std;

void solve() {
    int n;
    cin >> n;

    int mn = INT_MAX, mx = INT_MIN;
    for (int i = 0; i < n; i++) {
        int v;
        cin >> v;
        mn = min(mn, v);
        mx = max(mx, v);
    }

    cout << mn << " " << mx << "\n";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t;
    cin >> t;
    while (t--) solve();
    return 0;
}
